class Solution {
    public int minInsertions(String s) {
        int ans = 0, a = 0;
        for (char c : s.toCharArray()) {
            if (c == '(') {
                if (a % 2 > 0) {
                    ans++;
                }
                a += 2;
            } else {
                a--;
                if (a < 0) {
                    ans++;
                    a += 2;
                }
            }
        }
        return ans + a;
    }
}
